import springLogo from '../../assets/with_Spring_removebg.png';

const UserHeader = () => {
    return(
        <header className="w-full h-72 bg-sky-400 flex items-start">
            <div className="container mx-auto px-4 flex items-center">
                <span className="flex-shrink-0">
                    <img src={springLogo} alt="Spring 로고" className="h-44 w-44 object-contain mt-52 mr-5"/>
                </span>
                <span className="ml-4">
                    <input className="rounded-lg w-128 h-10 mt-8" name="allSearch"/>
                </span>
            </div>

        </header>

    )


}

export default UserHeader;
